// Structure Parsed Items → flat rows for Sheets
const phone    = $('Wati Trigger').first().json.waId || $('Wati Trigger1').item.json.from || 'unknown';
const userName = $('Wati Trigger').first().json.senderName || 'Shopper';
const now      = new Date();
const dateStr  = now.toISOString().split('T')[0].replace(/-/g, '');
const rand     = Math.random().toString(36).substring(2, 6).toUpperCase();
const listId   = `LST-${dateStr}-${rand}`;

const raw = $json?.choices?.[0]?.message?.content || '[]';
let items = [];
try { items = JSON.parse(raw); } catch(e) {
  const m = raw.match(/\[[\s\S]*\]/);
  if (m) { try { items = JSON.parse(m[0]); } catch(e2) {} }
}

if (!items || items.length === 0) {
  return [{ json: {
    phone, userName, listId, itemCount: 0, rows: [], isFirst: true,
    ackMessage: `⚠️ Could not parse your list. Please try:\n*list: milk 2L, eggs 12, bread, rice 5kg*`
  }}];
}

const rows = items.map(it => ({
  listId, phone, userName,
  item:     (it.item     || 'item').toLowerCase(),
  qty:       it.qty      || 1,
  unit:      it.unit     || 'pcs',
  category:  it.category || 'Other',
  addedAt:   now.toISOString(),
  status:   'Active'
}));

const catEmoji = { Grocery:'🛒️', Dairy:'🥛', Produce:'🥦', Meat:'🥩', Beverages:'🥤', Household:'🏠', 'Personal Care':'🧴', Electronics:'📱', Other:'📦' };

const itemLines = items.map((it, i) =>
  `  ${i+1}. ${catEmoji[it.category]||'📦'} ${it.item} — ${it.qty} ${it.unit}`
);

const ackMessage = [
  `✅ *Shopping List Saved!*`,
  `🗂️ List ID: \`${listId}\``,
  '',
  `📦 *${items.length} item${items.length > 1 ? 's' : ''} added:*`,
  ...itemLines,
  '',
  '━━━━━━━━━━━━━━━━━━',
  '🔍 Send *compare* → AI finds best prices now',
  '💰 Send *deals* → view saved deals',
  '📋 Send *mylist* → view current list'
].join('\n');

return rows.map((row, i) => ({ json: { ...row, ackMessage: i === 0 ? ackMessage : null, isFirst: i === 0, phone, listId, itemCount: items.length } }));

const phone    = $('Wati Trigger').first().json.waId || $('Wati Trigger1').item.json.from;
const userName =  $('Wati Trigger').first().json.senderName|| 'Shopper';
const items    = $input.all().filter(r => r.json.phone === phone && (r.json.status||'').toLowerCase() === 'active');

if (items.length === 0) {
  return [{ json: { phone, msg: `📋 *Your list is empty, ${userName}!*\n\nAdd items with:\n*list: milk 2L, eggs 12, bread, rice 5kg*` } }];
}

const catEmoji = { Grocery:'🛒️', Dairy:'🥛', Produce:'🥦', Meat:'🥩', Beverages:'🥤', Household:'🏠', 'Personal Care':'🦺', Electronics:'📱', Other:'📦' };
const byCategory = {};
for (const r of items) {
  const c = r.json.category || 'Other';
  if (!byCategory[c]) byCategory[c] = [];
  byCategory[c].push(r.json);
}

const lines = [`📋 *Your Shopping List*`, `👤 ${userName}`, ''];
for (const [cat, rows] of Object.entries(byCategory)) {
  lines.push(`${catEmoji[cat]||'📦'} *${cat}*`);
  for (const it of rows) lines.push(`  • ${it.item} — ${it.qty} ${it.unit}`);
  lines.push('');
}
lines.push(`📦 *Total: ${items.length} items*`);
lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('Send *compare* to find best prices 🔍');

return [{ json: { phone, msg: lines.join('\n') } }];

const phone    = $('Wati Trigger').first().json.waId || $('Wati Trigger1').item.json.from;
const userName = $('Wati Trigger').first().json.senderName || 'Shopper';
const allRows  = $input.all();

const myDeals = allRows.filter(r => r.json.phone === phone).sort((a,b)=>new Date(b.json.foundAt)-new Date(a.json.foundAt));
const seen = new Set();
const latest = myDeals.filter(r => { if (seen.has(r.json.item)) return false; seen.add(r.json.item); return true; });

if (latest.length === 0) {
  return [{ json: { phone, msg: `💰 *No saved deals yet, ${userName}!*\n\nSend *compare* to find the best prices for your list.` } }];
}

const lines = [`💰 *Your Saved Deals*`, `👤 ${userName}`, ''];
for (const r of latest) {
  const saving = parseFloat($input.first().json.savingPct) > 0 ? ` 🏷️ Save ${r.json.savingPct}%` : '';
  const dt = r.json.foundAt ? new Date(r.json.foundAt).toLocaleDateString('en-IN',{day:'numeric',month:'short'}) : '';
  lines.push(`🛒 *${r.json.item}*`);
  lines.push(`  ✅ ${r.json.storeName} — ₹${r.json.price}${saving}`);
  if (r.json.url) lines.push(`  🔗 ${r.json.url}`);
  lines.push(`  📅 Found: ${dt}`);
  lines.push('');
}
lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('Send *compare* to refresh prices 🔄');
return [{ json: { phone, msg: lines.join('\n') } }];

const phone = $json.waId || $json.from;
const name  = $json.senderName || 'Shopper';
return [{ json: { phone, msg: `🗑️ *List cleared, ${name}!*

Start fresh anytime:
*list: item1, item2, item3*` } }];

// Prepare one search query per item for this user
const phone =  $('Intent Router1').first().json.waId|| $('Wati Trigger1').item.json.from;
const rows  = $input.all().filter(r => r.json.phone === phone && (r.json.status||'').toLowerCase() === 'active');

if (rows.length === 0) {
  return [{ json: { phone, noItems: true, searchQuery: null,
    errMsg: `📋 *Your list is empty!*\n\nAdd items first with: *list: milk 2L, eggs*`
  }}];
}

return rows.map(r => ({
  json: {
    phone,
    userName:    r.json.userName,
    listId:      r.json.listId,
    item:        r.json.item,
    qty:         r.json.qty,
    unit:        r.json.unit,
    category:    r.json.category,
    searchQuery: `best price ${r.json.item} ${r.json.qty}${r.json.unit} buy online India`,
    noItems:     false
  }
}));

