// Parse deal, build item card, prepare Sheets row
const raw = $json?.choices?.[0]?.message?.content || '{}';
let d = {};
try { d = JSON.parse(raw); } catch(e) { const m = raw.match(/\{[\s\S]*\}/); if(m){try{d=JSON.parse(m[0]);}catch(e2){}} }

const src  = $('Prepare Search Queries1').item.json;
const best = d.bestDeal   || {};
const alts = d.alternatives || [];
const now  = new Date();

const saveBadge = (best.savingPct||0) > 0 ? ` 🏷️ -${best.savingPct}%` : '';
const altLines  = alts.slice(0,2).map(a => `    • ${a.storeName}: ₹${a.price}`).join('\n');

const itemCard = [
  `\n🛒 *${src.item}* (${src.qty} ${src.unit})`,
  `  ✅ *${best.storeName||'Unknown'}* — ₹${best.price||'N/A'}${saveBadge}`,
  altLines ? `  Others:\n${altLines}` : '',
  best.url ? `  🔗 ${best.url}` : ''
].filter(Boolean).join('\n');

return [{ json: {
  listId:        src.listId,
  phone:         src.phone,
  userName:      src.userName,
  item:          src.item,
  qty:           src.qty,
  unit:          src.unit,
  storeName:     best.storeName     || 'Unknown',
  price:         best.price         || 0,
  originalPrice: best.originalPrice || best.price || 0,
  savingPct:     best.savingPct     || 0,
  currency:      best.currency      || 'INR',
  url:           best.url           || '',
  summary:       d.summary          || '',
  confidence:    d.confidence        || 'low',
  alternatives:  JSON.stringify(alts),
  foundAt:       now.toISOString(),
  alertSent:     'No',
  itemCard
}}];

// Aggregate all processed deal items into one comparison card
const all = $input.all();
if (!all || all.length === 0) return [{ json: { phone:'', card:'No deals found.' } }];

const phone    = all[0].json.phone;
const userName = all[0].json.userName;
const now      = new Date();

let totalBest = 0, totalOrig = 0;
const cards = all.map(r => { totalBest += parseFloat(r.json.price||0); totalOrig += parseFloat(r.json.originalPrice||r.json.price||0); return r.json.itemCard; }).join('\n');

const saved   = totalOrig - totalBest;
const savePct = totalOrig > 0 ? Math.round((saved / totalOrig) * 100) : 0;
const hiConf  = all.filter(r => r.json.confidence === 'high').length;

const lines = [
  `🔍 *Price Comparison Report*`,
  `👤 ${userName} · ${now.toLocaleDateString('en-IN',{day:'numeric',month:'short'})}`,
  cards,
  '━━━━━━━━━━━━━━━━━━',
  `💰 *Estimated Total: ₹${totalBest.toFixed(0)}*`,
  saved > 0 ? `🏷️ *You could save: ₹${saved.toFixed(0)} (${savePct}%)*` : '',
  `ℹ️ ${hiConf}/${all.length} prices high-confidence`,
  '',
  'Prices are live estimates — verify before purchase.',
  'Send *deals* anytime to review saved deals.'
].filter(l => l !== '').join('\n');

return [{ json: { phone, card: lines } }];

// Build personalised daily deal alerts
const allRows = $input.all();

const alertable = allRows.filter(r => r.json.alertSent === 'No' && parseFloat(r.json.savingPct||0) >= 10);
if (alertable.length === 0) return [{ json: { message: 'No deals to alert today', count: 0 } }];

const byPhone = {};
for (const r of alertable) {
  const p = r.json.phone;
  if (!byPhone[p]) byPhone[p] = { phone: p, userName: r.json.userName, deals: [] };
  byPhone[p].deals.push(r.json);
}

return Object.values(byPhone).map(user => {
  const top = user.deals.sort((a,b)=>parseFloat(b.savingPct)-parseFloat(a.savingPct)).slice(0,5);
  const lines = [
    `🔥 *Daily Deal Alert!*`,
    `👋 Hi *${user.userName}!* Best prices found for your list:`,
    ''
  ];
  for (const d of top) {
    lines.push(`🛒 *${d.item}* — ₹${d.price} at *${d.storeName}*`);
    lines.push(`   🏷️ Save ${d.savingPct}% vs original price`);
    if (d.url) lines.push(`   🔗 ${d.url}`);
    lines.push('');
  }
  lines.push('━━━━━━━━━━━━━━━━━━');
  lines.push('Send *compare* to refresh prices anytime 🔄');
  return { json: { phone: user.phone, alertMessage: lines.join('\n'), dealCount: top.length } };
});
